\begin{aligned}3^{2x} + 19 &= 10^x \text{ Original equation} \text{ Taking the natural logarithm of both sides: }\\ \ln(3^{2x} + 19) &= \ln(10^x) \\ \ln(3^{2x}) + \ln(19) &= x\ln(10) \\ \ln(9^x) + \ln(19) &= x\ln(10) \\ x\ln(9) + \ln(19) &= x\ln(10) \\ \ln(19) &= x\ln(10) - x\ln(9) \\ \ln(19) &= x[\ln(10) - \ln(9)] \\ \ln(19) &= x\ln\left(\frac{10}{9}\right) \\ x &= \frac{\ln(19)}{\ln\left(\frac{10}{9}\right)}\end{aligned}
